SELECT hand_name
FROM poker_hands
WHERE hand_popularity = (SELECT MAX(hand_popularity) FROM poker_hands);

SELECT hand_name
FROM poker_hands
WHERE payout_5 = (
    SELECT MAX(payout_5) 
    FROM poker_hands
) 
AND hand_popularity = (
    SELECT MAX(hand_popularity) 
    FROM poker_hands
);

SELECT payout_1 AS total_payout
FROM poker_hands
WHERE hand_id = 1;

SELECT hand_name, payout_5, hand_difficulty
FROM poker_hands
ORDER BY hand_difficulty DESC;

SELECT hand_id, hand_name, payout_1, payout_2, hand_difficulty
FROM poker_hands
ORDER BY hand_difficulty DESC;

SELECT hand_name, payout_1, payout_2, payout_3, payout_4, payout_5
FROM poker_hands
ORDER BY hand_difficulty ASC;

SELECT AVG(payout_1) AS average_payout
FROM poker_hands
WHERE hand_name = 'Four Deuces';
